import React, { useState, useEffect, useCallback } from 'react';
import { Container, Card, Form, Button, Row, Col, Alert, Table, Badge } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const ML_PER_GLASS = 250;

const WaterLog = () => {
  const { token, authFetch } = useAuth();
  const navigate = useNavigate();
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [waterTasks, setWaterTasks] = useState([]);
  const [completedTasks, setCompletedTasks] = useState([]);
  const [complianceScore, setComplianceScore] = useState(0);
  const [totalTasks, setTotalTasks] = useState(0);
  const [encouragement, setEncouragement] = useState('');
  const [rewardImage, setRewardImage] = useState('');

  const loadToday = useCallback(async () => {
    const res = await authFetch('/api/water');
    if (res.status === 401) {
      navigate('/login');
      return;
    }
    const data = await res.json();
    if (!res.ok) {
      setError(data.error || 'Failed to load water tasks');
      return;
    }
    setWaterTasks(data.water_tasks || []);
    setCompletedTasks(data.water_tasks?.filter(task => task.completed) || []);
    setComplianceScore(data.compliance_score || 0);
    setTotalTasks(data.total_tasks || 0);
  }, [authFetch, navigate]);

  useEffect(() => {
    if (!token) {
      navigate('/login');
      return;
    }
    loadToday();
  }, [token, navigate, loadToday]);

  const handleTaskComplete = async (taskId) => {
    setError('');
    setLoading(true);
    setEncouragement('');
    setRewardImage('');
    
    try {
      let res;
      if (token) {
        // Use authenticated fetch
        res = await authFetch('/api/water', {
          method: 'POST',
          body: { task_id: taskId },
        });
      } else {
        // Use simple fetch without authentication
        res = await fetch('http://localhost:5000/api/water', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ task_id: taskId }),
        });
      }
      
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || 'Could not complete water task');
        return;
      }
      
      // Show encouragement and reward
      setEncouragement(data.encouragement || 'Water task completed!');
      setRewardImage(data.reward_image || '');
      
      // Reload tasks
      if (token) {
        await loadToday();
      } else {
        // Reload without auth
        const reloadRes = await fetch('http://localhost:5000/api/water');
        if (reloadRes.ok) {
          const reloadData = await reloadRes.json();
          setWaterTasks(reloadData.water_tasks || []);
          setCompletedTasks(reloadData.water_tasks?.filter(task => task.completed) || []);
          setComplianceScore(reloadData.compliance_score || 0);
          setTotalTasks(reloadData.total_tasks || 0);
        }
      }
    } catch {
      setError('Network error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container className="py-4">
      <h2 className="mb-4">💧 Water Tasks - Tick to Complete</h2>
      
      {error && <Alert variant="danger">{error}</Alert>}
      
      {/* Encouragement and Reward Section */}
      {encouragement && (
        <Alert variant="success" className="mb-4">
          <div className="d-flex align-items-center">
            <div className="flex-grow-1">
              <h5 className="mb-2">{encouragement}</h5>
              {rewardImage && (
                <img 
                  src={rewardImage} 
                  alt="Reward" 
                  className="img-fluid rounded" 
                  style={{ maxWidth: '200px', height: 'auto' }}
                />
              )}
            </div>
          </div>
        </Alert>
      )}

      {/* Progress Overview */}
      <Card className="mb-4">
        <Card.Body>
          <Card.Title>Today's Progress</Card.Title>
          <Row className="text-center">
            <Col md={4}>
              <h4>{completedTasks.length}/{totalTasks}</h4>
              <p className="text-muted">Tasks Completed</p>
            </Col>
            <Col md={4}>
              <h4>{complianceScore}%</h4>
              <p className="text-muted">Compliance Score</p>
            </Col>
            <Col md={4}>
              <h4>{(completedTasks.length * ML_PER_GLASS).toLocaleString()} ml</h4>
              <p className="text-muted">Water Intake</p>
            </Col>
          </Row>
        </Card.Body>
      </Card>

      {/* Water Tasks */}
      <Row>
        <Col md={12}>
          <Card>
            <Card.Body>
              <Card.Title>Today's Water Tasks</Card.Title>
              {waterTasks.length === 0 ? (
                <Alert variant="info">
                  No water tasks available. Please get your diet recommendations first.
                </Alert>
              ) : (
                <div className="task-list">
                  {waterTasks.map((task) => (
                    <div key={task.id} className="border rounded p-3 mb-3">
                      <div className="d-flex align-items-center justify-content-between">
                        <div className="d-flex align-items-center">
                          <span className="me-3" style={{ fontSize: '1.5rem' }}>
                            {task.icon}
                          </span>
                          <div>
                            <h6 className="mb-1">{task.time}</h6>
                            <p className="mb-0 text-muted">
                              {task.glasses} glasses - {task.purpose}
                            </p>
                            {task.completed_at && (
                              <small className="text-success">
                                Completed at {new Date(task.completed_at).toLocaleTimeString()}
                              </small>
                            )}
                          </div>
                        </div>
                        <div className="d-flex align-items-center">
                          {task.completed ? (
                            <Badge bg="success" className="me-2">Completed</Badge>
                          ) : (
                            <Button
                              variant="primary"
                              size="sm"
                              onClick={() => handleTaskComplete(task.id)}
                              disabled={loading}
                            >
                              {loading ? 'Completing...' : 'Complete'}
                            </Button>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
};

export default WaterLog;
